// lib/logging/log_entry.dart
class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;
  final String? errorDetails;
  final String? stackTrace;

  LogEntry({
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.errorDetails,
    this.stackTrace,
  }) : timestamp = DateTime.now();

  Map<String, dynamic> toJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'category': category,
        'message': message,
        if (metadata != null) 'metadata': metadata,
        if (errorDetails != null) 'error': errorDetails,
        if (stackTrace != null) 'stackTrace': stackTrace,
      };

  @override
  String toString() =>
      '[${timestamp.toIso8601String()}] [${level.name.toUpperCase()}] [$category] $message'
      '${metadata != null ? ' | metadata: $metadata' : ''}'
      '${errorDetails != null ? ' | error: $errorDetails' : ''}';
}

// lib/logging/sensitive_data_sanitizer.dart
class SensitiveDataSanitizer {
  static const _redacted = '[REDACTED]';
  static const _tokenPreviewLength = 4;

  // Keys that should ALWAYS be fully redacted
  static const _fullyRedactedKeys = {
    'password',
    'passwd',
    'secret',
    'credit_card',
    'creditCard',
    'card_number',
    'cardNumber',
    'cvv',
    'cvc',
    'ssn',
    'social_security',
    'pin',
    'private_key',
    'privateKey',
    'client_secret',
    'clientSecret',
    'api_key',
    'apiKey',
    'api_secret',
    'apiSecret',
    'refresh_token',
    'refreshToken',
    'id_token',
    'idToken',
    'session_id',
    'sessionId',
    'cookie',
    'set-cookie',
  };

  // Keys that get partially masked (show last few chars for debugging)
  static const _partiallyMaskedKeys = {
    'authorization',
    'token',
    'access_token',
    'accessToken',
    'bearer',
    'x-api-key',
  };

  // Keys containing PII that should be redacted
  static const _piiKeys = {
    'email',
    'phone',
    'phone_number',
    'phoneNumber',
    'address',
    'date_of_birth',
    'dateOfBirth',
    'dob',
    'first_name',
    'firstName',
    'last_name',
    'lastName',
    'full_name',
    'fullName',
    'name',
  };

  /// Sanitize a map of data, removing or masking sensitive fields
  static Map<String, dynamic> sanitizeMap(Map<String, dynamic> data) {
    final sanitized = <String, dynamic>{};
    for (final entry in data.entries) {
      sanitized[entry.key] = _sanitizeValue(entry.key, entry.value);
    }
    return sanitized;
  }

  /// Sanitize HTTP headers
  static Map<String, dynamic> sanitizeHeaders(Map<String, dynamic> headers) {
    final sanitized = <String, dynamic>{};
    for (final entry in headers.entries) {
      final lowerKey = entry.key.toLowerCase();
      if (_fullyRedactedKeys.contains(lowerKey)) {
        sanitized[entry.key] = _redacted;
      } else if (_partiallyMaskedKeys.contains(lowerKey)) {
        sanitized[entry.key] = _maskToken(entry.value.toString());
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  static dynamic _sanitizeValue(String key, dynamic value) {
    final lowerKey = key.toLowerCase();

    if (_fullyRedactedKeys.contains(lowerKey)) {
      return _redacted;
    }

    if (_partiallyMaskedKeys.contains(lowerKey)) {
      return _maskToken(value.toString());
    }

    if (_piiKeys.contains(lowerKey)) {
      return _redacted;
    }

    if (value is Map<String, dynamic>) {
      return sanitizeMap(value);
    }

    if (value is List) {
      return value.map((item) {
        if (item is Map<String, dynamic>) return sanitizeMap(item);
        return item;
      }).toList();
    }

    return value;
  }

  /// Show only last N characters of a token for correlation purposes
  static String _maskToken(String token) {
    if (token.length <= _tokenPreviewLength) return _redacted;
    final suffix = token.substring(token.length - _tokenPreviewLength);
    return '***...$suffix';
  }

  /// Create a safe user identifier for logs (not the full ID)
  static String safeUserId(String userId) {
    if (userId.length <= 4) return '****';
    return '${userId.substring(0, 2)}***${userId.substring(userId.length - 2)}';
  }
}

// lib/logging/log_buffer.dart
import 'dart:collection';

class LogBuffer {
  final int maxSize;
  final Queue<LogEntry> _buffer = Queue<LogEntry>();

  LogBuffer({this.maxSize = 500});

  void add(LogEntry entry) {
    if (_buffer.length >= maxSize) {
      _buffer.removeFirst();
    }
    _buffer.add(entry);
  }

  List<LogEntry> getRecent({int count = 50}) {
    final entries = _buffer.toList();
    final start = entries.length > count ? entries.length - count : 0;
    return entries.sublist(start);
  }

  List<LogEntry> getByCategory(String category) {
    return _buffer.where((e) => e.category == category).toList();
  }

  List<LogEntry> getByLevel(LogLevel minLevel) {
    return _buffer.where((e) => e.level.index >= minLevel.index).toList();
  }

  void clear() => _buffer.clear();

  int get length => _buffer.length;
}

