class AppLogger {
  static AppLogger? _instance;
  static AppLogger get instance => _instance ??= AppLogger._();

  AppLogger._();

  LogLevel _minLevel = kDebugMode ? LogLevel.verbose : LogLevel.info;
  final LogBuffer _buffer = LogBuffer(maxSize: 1000);
  bool _sanitizeLogs = true; // ALWAYS true in production

  // Remote log sink callback (e.g., send to Sentry, Datadog, etc.)
  void Function(LogEntry entry)? onRemoteLog;

  void configure({
    LogLevel? minLevel,
    bool? sanitize,
    void Function(LogEntry)? remoteLogSink,
  }) {
    if (minLevel != null) _minLevel = minLevel;
    // SECURITY: sanitization cannot be disabled in release mode
    if (sanitize != null && kDebugMode) {
      _sanitizeLogs = sanitize;
    } else {
      _sanitizeLogs = true;
