    onRemoteLog = remoteLogSink;
  }

  LogBuffer get buffer => _buffer;

  void _log(LogEntry entry) {
    if (entry.level.index < _minLevel.index) return;

    _buffer.add(entry);

    // Console output - use debugPrint for safe output that won't overflow
    if (kDebugMode) {
      debugPrint(entry.toString());
    }

    // Remote logging for warning+ levels in production
    if (!kDebugMode && entry.level.index >= LogLevel.warning.index) {
      onRemoteLog?.call(entry);
    }

    // Always send errors and fatals remotely
    if (entry.level.index >= LogLevel.error.index) {
      onRemoteLog?.call(entry);
    }
  }

  void verbose(String category, String message, {Map<String, dynamic>? data}) {
    _log(LogEntry(
      level: LogLevel.verbose,
      category: category,
      message: message,
      metadata: data != null ? _maybeSanitize(data) : null,
    ));
  }

  void debug(String category, String message, {Map<String, dynamic>? data}) {
    _log(LogEntry(
      level: LogLevel.debug,
      category: category,
      message: message,
      metadata: data != null ? _maybeSanitize(data) : null,
    ));
  }

  void info(String category, String message, {Map<String, dynamic>? data}) {
    _log(LogEntry(
      level: LogLevel.info,
      category: category,
      message: message,
      metadata: data != null ? _maybeSanitize(data) : null,
    ));
  }

  void warning(String category, String message,
      {Map<String, dynamic>? data, Object? error}) {
    _log(LogEntry(
      level: LogLevel.warning,
      category: category,
      message: message,
      metadata: data != null ? _maybeSanitize(data) : null,
      errorDetails: error?.toString(),
    ));
  }

  void error(String category, String message,
      {Map<String, dynamic>? data, Object? error, StackTrace? stackTrace}) {
    _log(LogEntry(
      level: LogLevel.error,
