// lib/logging/http_logging_interceptor.dart
// For use with the `dio` HTTP client package

class HttpLoggingInterceptor {
  final AppLogger _logger = AppLogger.instance;
  static const _category = 'HTTP';

  /// Call this before sending an HTTP request
  void onRequest({
    required String method,
    required String url,
    Map<String, dynamic>? headers,
    dynamic body,
    Map<String, dynamic>? queryParameters,
  }) {
    final sanitizedHeaders =
        headers != null ? SensitiveDataSanitizer.sanitizeHeaders(headers) : null;

    final sanitizedBody = body is Map<String, dynamic>
        ? SensitiveDataSanitizer.sanitizeMap(body)
        : body != null
            ? '[body: ${body.runtimeType}]'
            : null;

    _logger.info(_category, '--> $method $url', data: {
      if (sanitizedHeaders != null) 'headers': sanitizedHeaders,
      if (sanitizedBody != null) 'body': sanitizedBody,
      if (queryParameters != null) 'query': queryParameters,
      'timestamp': DateTime.now().toIso8601String(),
    });
  }

  /// Call this when an HTTP response is received
  void onResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, dynamic>? headers,
    dynamic body,
    Duration? duration,
  }) {
    final sanitizedHeaders =
        headers != null ? SensitiveDataSanitizer.sanitizeHeaders(headers) : null;

    final sanitizedBody = body is Map<String, dynamic>
        ? SensitiveDataSanitizer.sanitizeMap(body)
        : body != null
            ? '[body: ${body.runtimeType}, length: ${body.toString().length}]'
            : null;

    final level = statusCode >= 400 ? LogLevel.warning : LogLevel.info;

    final entry = LogEntry(
      level: level,
      category: _category,
      message:
          '<-- $statusCode $method $url${duration != null ? ' (${duration.inMilliseconds}ms)' : ''}',
      metadata: {
        'statusCode': statusCode,
        if (sanitizedHeaders != null) 'headers': sanitizedHeaders,
        if (sanitizedBody != null) 'body': sanitizedBody,
        if (duration != null) 'durationMs': duration.inMilliseconds,
      },
    );

    // Log slow requests as warnings
    if (duration != null && duration.inMilliseconds > 3000) {
      _logger.warning(_category, 'Slow request: $method $url took ${duration.inMilliseconds}ms');
    }

    AppLogger.instance._log(entry);
  }

  /// Call this when an HTTP error occurs
  void onError({
    required String method,
    required String url,
    int? statusCode,
    Object? error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      _category,
      '<-- ERROR $method $url${statusCode != null ? ' ($statusCode)' : ''}',
      error: error,
      stackTrace: stackTrace,
      data: {
        if (statusCode != null) 'statusCode': statusCode,
      },
    );
  }
}

// lib/logging/database_logger.dart

class DatabaseLogger {
  final AppLogger _logger = AppLogger.instance;
  static const _category = 'DATABASE';

  void logQuery({
    required String operation,
    required String table,
    Map<String, dynamic>? parameters,
    int? rowsAffected,
    Duration? duration,
  }) {
    // Sanitize any parameters that might contain sensitive data
    final sanitizedParams = parameters != null
        ? SensitiveDataSanitizer.sanitizeMap(parameters)
        : null;

    _logger.debug(_category, '$operation on $table', data: {
      'operation': operation,
      'table': table,
      if (sanitizedParams != null) 'parameters': sanitizedParams,
      if (rowsAffected != null) 'rowsAffected': rowsAffected,
      if (duration != null) 'durationMs': duration.inMilliseconds,
    });

    // Warn on slow queries
    if (duration != null && duration.inMilliseconds > 500) {
      _logger.warning(
          _category, 'Slow query: $operation on $table took ${duration.inMilliseconds}ms');
    }
  }

  void logError({
    required String operation,
    required String table,
    required Object error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      _category,
      'Database error during $operation on $table',
      error: error,
      stackTrace: stackTrace,
    );
  }

  void logMigration({
    required int fromVersion,
    required int toVersion,
    bool success = true,
    Object? error,
  }) {
    if (success) {
      _logger.info(_category, 'Migration successful: v$fromVersion -> v$toVersion');
    } else {
      _logger.error(
        _category,
        'Migration failed: v$fromVersion -> v$toVersion',
        error: error,
      );
    }
  }
}

// lib/logging/auth_logger.dart

class AuthLogger {
  final AppLogger _logger = AppLogger.instance;
  static const _category = 'AUTH';

  /// Log a login attempt - NEVER log credentials
  void logLoginAttempt({
    required String method, // e.g., 'email', 'google', 'apple', 'biometric'
    String? userId,
  }) {
    _logger.info(_category, 'Login attempt via $method', data: {
      'method': method,
      if (userId != null) 'userId': SensitiveDataSanitizer.safeUserId(userId),
      'timestamp': DateTime.now().toIso8601String(),
    });
  }

  /// Log a successful login
  void logLoginSuccess({
    required String method,
    String? userId,
  }) {
    _logger.info(_category, 'Login successful via $method', data: {
      'method': method,
      if (userId != null) 'userId': SensitiveDataSanitizer.safeUserId(userId),
    });
  }

  /// Log a failed login - log the reason, NEVER the credentials
  void logLoginFailure({
    required String method,
    required String reason, // e.g., 'invalid_credentials', 'account_locked', 'mfa_required'
    String? errorCode,
  }) {
    _logger.warning(_category, 'Login failed via $method: $reason', data: {
      'method': method,
      'reason': reason,
      if (errorCode != null) 'errorCode': errorCode,
    });
  }

  /// Log token refresh events - NEVER log the actual tokens
  void logTokenRefresh({
    required bool success,
    String? errorReason,
  }) {
    if (success) {
      _logger.debug(_category, 'Token refreshed successfully');
    } else {
      _logger.warning(_category, 'Token refresh failed: ${errorReason ?? "unknown"}');
    }
  }

  /// Log logout events
  void logLogout({
    required String reason, // 'user_initiated', 'session_expired', 'forced'
  }) {
    _logger.info(_category, 'Logout: $reason', data: {
      'reason': reason,
    });
  }

  /// Log permission/authorization events
  void logAuthorizationCheck({
    required String resource,
    required String action,
    required bool allowed,
  }) {
    final level = allowed ? LogLevel.debug : LogLevel.warning;
    final entry = LogEntry(
      level: level,
      category: _category,
      message: 'Authorization ${allowed ? "granted" : "denied"}: $action on $resource',
      metadata: {
        'resource': resource,
        'action': action,
        'allowed': allowed,
      },
    );
    AppLogger.instance._log(entry);
  }

  /// Log MFA events
  void logMfaEvent({
    required String event, // 'challenge_sent', 'verified', 'failed'
    required String method, // 'sms', 'totp', 'email'
  }) {
    _logger.info(_category, 'MFA $event via $method', data: {
      'event': event,
      'method': method,
    });
  }
}

