// lib/logging/app_health_monitor.dart

class AppHealthMonitor {
  final AppLogger _logger = AppLogger.instance;
  static const _category = 'HEALTH';

  void logAppStartup({required Duration duration}) {
    _logger.info(_category, 'App started in ${duration.inMilliseconds}ms', data: {
      'startupMs': duration.inMilliseconds,
    });
  }

  void logAppLifecycleChange(String state) {
    _logger.info(_category, 'App lifecycle: $state');
  }

  void logMemoryWarning() {
    _logger.warning(_category, 'Memory warning received');
  }

  void logFrameDrop({required int droppedFrames, required Duration duration}) {
    _logger.warning(_category, 'Frame drop detected', data: {
      'droppedFrames': droppedFrames,
      'durationMs': duration.inMilliseconds,
    });
  }

  void logConnectivityChange({required String status}) {
    _logger.info(_category, 'Connectivity changed: $status');
  }

  void logCrash({
    required Object error,
    required StackTrace stackTrace,
  }) {
    _logger.fatal(
      _category,
      'App crash detected',
      error: error,
      stackTrace: stackTrace,
    );
  }

  /// Generate a health report from buffered logs
  Map<String, dynamic> generateHealthReport() {
    final buffer = _logger.buffer;
    final errors = buffer.getByLevel(LogLevel.error);
    final warnings = buffer.getByLevel(LogLevel.warning);
    final httpLogs = buffer.getByCategory('HTTP');

    final slowRequests = httpLogs
        .where((e) =>
            e.metadata != null &&
            e.metadata!['durationMs'] != null &&
            (e.metadata!['durationMs'] as int) > 2000)
        .length;

    return {
      'totalLogs': buffer.length,
      'errors': errors.length,
      'warnings': warnings.length,
      'httpRequests': httpLogs.length,
      'slowRequests': slowRequests,
      'generatedAt': DateTime.now().toIso8601String(),
    };
  }
}

// lib/logging/debug_log_exporter.dart
// For sharing logs during debugging (e.g., user can export and send to support)

import 'dart:convert';

class DebugLogExporter {
  final AppLogger _logger = AppLogger.instance;

  /// Export recent logs as sanitized JSON string
  /// Safe to share because all sensitive data is already sanitized at log time
  String exportRecentLogs({int count = 100}) {
    final entries = _logger.buffer.getRecent(count: count);
    final jsonEntries = entries.map((e) => e.toJson()).toList();
    return const JsonEncoder.withIndent('  ').convert({
      'exportedAt': DateTime.now().toIso8601String(),
      'logCount': jsonEntries.length,
      'logs': jsonEntries,
    });
  }

  /// Export only error logs
  String exportErrorLogs() {
    final entries = _logger.buffer.getByLevel(LogLevel.error);
    final jsonEntries = entries.map((e) => e.toJson()).toList();
    return const JsonEncoder.withIndent('  ').convert({
      'exportedAt': DateTime.now().toIso8601String(),
      'logCount': jsonEntries.length,
      'logs': jsonEntries,
    });
  }
}

// lib/main.dart (example usage)
import 'package:flutter/material.dart';
import 'package:flutter/foundation.dart';

void main() {
  // Setup logging
  final logger = AppLogger.instance;
  logger.configure(
    minLevel: kDebugMode ? LogLevel.verbose : LogLevel.info,
    remoteLogSink: (entry) {
      // Send to your remote logging service (Sentry, Datadog, Crashlytics, etc.)
      // The entry is already sanitized - safe to transmit
      debugPrint('REMOTE LOG: ${entry.toJson()}');
    },
  );

  // Setup error handling
  FlutterError.onError = (details) {
    AppHealthMonitor().logCrash(
      error: details.exception,
      stackTrace: details.stack ?? StackTrace.current,
    );
  };

  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Logging Demo',
      home: const ExampleScreen(),
      navigatorObservers: [LoggingNavigatorObserver()],
    );
  }
}

class LoggingNavigatorObserver extends NavigatorObserver {
  final _uiLogger = UserInteractionLogger();

  @override
  void didPush(Route route, Route? previousRoute) {
    _uiLogger.logNavigation(
      from: previousRoute?.settings.name ?? 'unknown',
      to: route.settings.name ?? 'unknown',
      trigger: 'push',
    );
  }

  @override
  void didPop(Route route, Route? previousRoute) {
    _uiLogger.logNavigation(
      from: route.settings.name ?? 'unknown',
      to: previousRoute?.settings.name ?? 'unknown',
      trigger: 'pop',
    );
  }
}

