        'access_token': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.newtoken',
        'refresh_token': 'rt_longsecretrefreshtoken',
        'user': {
          'id': 'user123',
          'email': 'user@example.com',
          'name': 'John Doe',
        },
      },
      duration: const Duration(milliseconds: 245),
    );

    _authLogger.logLoginSuccess(method: 'email', userId: 'user123abc');
  }

  void _simulateDbOperation() {
    _uiLogger.logButtonTap(buttonName: 'db_query', screenName: 'ExampleScreen');

    final stopwatch = Stopwatch()..start();

    _dbLogger.logQuery(
      operation: 'SELECT',
      table: 'users',
      parameters: {
        'id': 'user123',
        'email': 'user@example.com',
        'password_hash': 'bcrypt\$2b\$12\$abc123',
      },
      rowsAffected: 1,
      duration: Duration(milliseconds: stopwatch.elapsedMilliseconds + 15),
    );
  }

  void _exportLogs() {
    _uiLogger.logButtonTap(buttonName: 'export_logs', screenName: 'ExampleScreen');

    final logs = _logExporter.exportRecentLogs();
    debugPrint('=== EXPORTED LOGS (sanitized) ===');
    debugPrint(logs);

    final healthReport = _healthMonitor.generateHealthReport();
    debugPrint('=== HEALTH REPORT ===');
    debugPrint(healthReport.toString());
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Production Logging Demo')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            const Padding(
              padding: EdgeInsets.all(16.0),
              child: Text(
                'All logging automatically sanitizes sensitive data.\n'
                'Passwords, tokens, PII are redacted or masked.\n'
                'Check debug console for output.',
                textAlign: TextAlign.center,
                style: TextStyle(fontSize: 14),
              ),
            ),
            const SizedBox(height: 20),
            ElevatedButton(
              onPressed: _simulateLogin,
              child: const Text('Simulate Login (check console)'),
            ),
            const SizedBox(height: 12),
            ElevatedButton(
              onPressed: _simulateDbOperation,
              child: const Text('Simulate DB Query (check console)'),
            ),
            const SizedBox(height: 12),
            ElevatedButton(
              onPressed: _exportLogs,
              child: const Text('Export Sanitized Logs'),
            ),
          ],
        ),
      ),
    );
  }
